"use client";
import { useState, useEffect } from "react";

const API_URL = "http://localhost:8000";

interface AnaliseResult {
  id: number;
  url: string;
  texto: string;
  grafo_tamanho: number;
  pred_upfd: string;
  cert_upfd: number;
  pred_bsky: string;
  cert_bsky: number;
  heuristica_final: number;
}

interface HistoryItem {
  id: number;
  url_bsky: string;
  texto_resumo: string;
  pred_upfd: string;
  pred_bsky: string;
  heuristica_final: number;
  data_consulta: string;
}

export default function Home() {
  const [url, setUrl] = useState("");
  const [loading, setLoading] = useState(false);
  const [loaderText, setLoaderText] = useState("Construindo o Grafo de Dispersão...");
  const [result, setResult] = useState<AnaliseResult | null>(null);
  const [history, setHistory] = useState<HistoryItem[]>([]);
  const [error, setError] = useState("");

  useEffect(() => {
    fetchHistory();
  }, []);

  async function fetchHistory() {
    try {
      const res = await fetch(`${API_URL}/api/history`);
      if (res.ok) {
        const data = await res.json();
        setHistory(data);
      }
    } catch { /* server offline */ }
  }

  async function analisar() {
    if (!url.includes("bsky.app")) {
      setError("Insira um link válido do Bluesky (bsky.app/profile/...)");
      return;
    }
    setError("");
    setResult(null);
    setLoading(true);
    setLoaderText("Construindo o Grafo de Dispersão...");

    const t1 = setTimeout(() => setLoaderText("Extraindo Embeddings Multilingual (BERT)..."), 2500);
    const t2 = setTimeout(() => setLoaderText("Calculando Pesos na Rede Neural Cruzada (GCN)..."), 5000);

    try {
      const res = await fetch(`${API_URL}/api/analyze`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ url }),
      });
      const data = await res.json();
      if (res.ok) {
        setResult(data);
        fetchHistory();
      } else {
        setError(data.detail || "Erro desconhecido");
      }
    } catch {
      setError("Erro de conexão com a API. Verifique se o backend FastAPI está rodando na porta 8000.");
    } finally {
      clearTimeout(t1);
      clearTimeout(t2);
      setLoading(false);
    }
  }

  const chanceColor = (v: number) =>
    v > 60 ? "text-red-400" : v < 40 ? "text-green-400" : "text-yellow-400";
  const barBg = (v: number) =>
    v > 60 ? "bg-red-500" : v < 40 ? "bg-green-500" : "bg-yellow-400";
  const predColor = (p: string) =>
    p === "FAKE NEWS" ? "text-red-400" : "text-green-400";

  return (
    <main className="min-h-screen flex flex-col items-center px-4 py-12 relative overflow-hidden">
      {/* Blobs de fundo */}
      <div className="pointer-events-none fixed inset-0 z-0">
        <div className="absolute top-[10%] left-[15%] w-[500px] h-[500px] rounded-full bg-[#0085ff]/10 blur-[120px]" />
        <div className="absolute bottom-[10%] right-[10%] w-[400px] h-[400px] rounded-full bg-[#00d2ff]/8 blur-[100px]" />
      </div>

      <div className="relative z-10 w-full max-w-5xl">
        {/* Header */}
        <header className="text-center mb-12 animate-fade-up">
          <h1 className="text-5xl md:text-6xl font-extrabold bg-gradient-to-r from-white to-cyan-400 bg-clip-text text-transparent tracking-tight">
            Truth GNN Analytics
          </h1>
          <p className="mt-2 text-slate-400 text-lg font-light">
            Análise Preditiva em Grafos &bull; UPFD vs MegaDataset &bull; TCC
          </p>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Painel Principal */}
          <div className="lg:col-span-2 rounded-3xl p-8 border border-white/10 bg-white/[0.03] backdrop-blur-2xl shadow-2xl animate-fade-up">
            {/* Input */}
            <div className="relative mb-5">
              <span className="absolute left-4 top-1/2 -translate-y-1/2 text-cyan-400 text-lg">🔗</span>
              <input
                id="bluesky-url-input"
                type="text"
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && analisar()}
                placeholder="Cole a URL de um post do Bluesky..."
                className="w-full pl-12 pr-4 py-4 rounded-xl bg-black/30 border border-white/10 text-white placeholder-slate-500 focus:outline-none focus:border-cyan-500 focus:ring-2 focus:ring-cyan-500/20 transition-all text-base"
              />
            </div>

            <button
              id="btn-analyze"
              onClick={analisar}
              disabled={loading}
              className="w-full py-4 rounded-xl font-semibold text-white bg-gradient-to-r from-blue-600 to-blue-800 hover:shadow-lg hover:shadow-cyan-500/20 hover:-translate-y-0.5 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-3 text-base"
            >
              {loading ? "Processando..." : "⚡ Gerar Tensor e Analisar"}
            </button>

            {error && (
              <div className="mt-4 p-4 rounded-xl bg-red-500/10 border border-red-500/30 text-red-300 text-sm">
                {error}
              </div>
            )}

            {/* Loader */}
            {loading && (
              <div className="flex flex-col items-center gap-4 py-10 animate-fade-up">
                <div className="flex gap-3">
                  <div className="w-4 h-4 rounded-full bg-cyan-400 animate-node" />
                  <div className="w-4 h-4 rounded-full bg-cyan-400 animate-node" style={{ animationDelay: "0.2s" }} />
                  <div className="w-4 h-4 rounded-full bg-cyan-400 animate-node" style={{ animationDelay: "0.4s" }} />
                </div>
                <span className="text-slate-400 text-sm tracking-wide">{loaderText}</span>
              </div>
            )}

            {/* Dashboard de Resultados */}
            {result && !loading && (
              <div className="mt-8 pt-6 border-t border-white/10 animate-fade-up">
                {/* Texto analisado */}
                <div className="mb-6 p-4 rounded-lg bg-white/[0.02] border-l-4 border-cyan-400 text-slate-300 text-sm italic">
                  &ldquo;{result.texto}&rdquo;
                  <div className="mt-2 text-xs text-cyan-500 not-italic">
                    Grafo: 1 Raiz + {result.grafo_tamanho - 1} Propagações
                  </div>
                </div>

                {/* Barra Heurística */}
                <div className="flex justify-between items-end mb-2">
                  <span className="text-lg font-semibold">Probabilidade de ser Fake News</span>
                  <span className={`text-4xl font-extrabold ${chanceColor(result.heuristica_final)}`}>
                    {result.heuristica_final}%
                  </span>
                </div>
                <div className="w-full h-4 rounded-full bg-black/50 overflow-hidden mb-8 shadow-inner">
                  <div
                    className={`h-full rounded-full ${barBg(result.heuristica_final)} animate-bar shadow-lg`}
                    style={{ width: `${result.heuristica_final}%` }}
                  />
                </div>

                {/* Cards dos Modelos */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {/* UPFD */}
                  <div className="rounded-2xl p-5 bg-black/20 border border-white/10 text-center hover:bg-black/30 transition-colors">
                    <div className="text-xs uppercase tracking-widest text-slate-400 mb-2 flex items-center justify-center gap-2">
                      🐦 IA Antiga (PolitiFact UPFD)
                    </div>
                    <div className={`text-2xl font-extrabold mb-1 ${predColor(result.pred_upfd)}`}>
                      {result.pred_upfd}
                    </div>
                    <div className="text-xs text-slate-500">
                      Probabilidade Tensor: {result.cert_upfd}%
                    </div>
                  </div>

                  {/* MegaDataset */}
                  <div className="rounded-2xl p-5 bg-black/20 border border-cyan-500/30 text-center hover:bg-black/30 transition-colors shadow-[inset_0_0_20px_rgba(0,133,255,0.05)]">
                    <div className="text-xs uppercase tracking-widest text-slate-400 mb-2 flex items-center justify-center gap-2">
                      ☁️ IA Tese (BSKY Mega Dataset)
                    </div>
                    <div className={`text-2xl font-extrabold mb-1 ${predColor(result.pred_bsky)}`}>
                      {result.pred_bsky}
                    </div>
                    <div className="text-xs text-slate-500">
                      Probabilidade Tensor: {result.cert_bsky}%
                    </div>
                    <div className="text-[10px] text-cyan-400 mt-2">
                      (Acurácia histórica de 80.4% em domínio)
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Sidebar: Feed Histórico do SQLite */}
          <div className="rounded-3xl p-6 border border-white/10 bg-white/[0.03] backdrop-blur-2xl shadow-2xl animate-fade-up" style={{ animationDelay: "0.2s" }}>
            <h2 className="text-lg font-bold mb-4 flex items-center gap-2">
              🕐 Histórico de Análises
            </h2>

            {history.length === 0 ? (
              <p className="text-slate-500 text-sm">Nenhuma análise ainda. Cole um link e analise!</p>
            ) : (
              <div className="flex flex-col gap-3 max-h-[600px] overflow-y-auto pr-1">
                {history.map((item) => (
                  <div
                    key={item.id}
                    className="p-3 rounded-xl bg-black/20 border border-white/5 hover:border-white/15 transition-colors cursor-pointer"
                    onClick={() => setUrl(item.url_bsky)}
                  >
                    <div className="text-xs text-slate-400 truncate mb-1">
                      {item.url_bsky}
                    </div>
                    <div className="text-sm text-slate-300 line-clamp-2 mb-2">
                      {item.texto_resumo}
                    </div>
                    <div className="flex justify-between items-center">
                      <span className={`text-xs font-bold ${
                        item.heuristica_final > 60 ? "text-red-400" :
                        item.heuristica_final < 40 ? "text-green-400" : "text-yellow-400"
                      }`}>
                        {item.heuristica_final}% Fake
                      </span>
                      <div className="flex gap-1">
                        <span className={`text-[10px] px-2 py-0.5 rounded-full ${
                          item.pred_bsky === "FAKE NEWS" ? "bg-red-500/20 text-red-300" : "bg-green-500/20 text-green-300"
                        }`}>
                          BSKY: {item.pred_bsky === "FAKE NEWS" ? "FAKE" : "REAL"}
                        </span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </main>
  );
}
